using System;
using System.Collections.Generic;
using System.Text.Json;
using System.Text.Json.Serialization;

namespace Azure.ResourceManager
{
    /// <summary>
    /// AOT-compatible converter for <see cref="ResponseError"/> which has an inaccessible internal converter.
    /// </summary>
    internal class AotResponseErrorConverter : JsonConverter<ResponseError>
    {
        public override ResponseError Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            using var doc = JsonDocument.ParseValue(ref reader);
            var root = doc.RootElement;
            string code = root.TryGetProperty("code", out var c) ? c.GetString() : null;
            string message = root.TryGetProperty("message", out var m) ? m.GetString() : null;
            return new ResponseError(code, message);
        }

        public override void Write(Utf8JsonWriter writer, ResponseError value, JsonSerializerOptions options)
        {
            writer.WriteStartObject();
            if (value.Code != null)
            {
                writer.WritePropertyName("code"u8);
                writer.WriteStringValue(value.Code);
            }
            if (value.Message != null)
            {
                writer.WritePropertyName("message"u8);
                writer.WriteStringValue(value.Message);
            }
            writer.WriteEndObject();
        }
    }

    [JsonSourceGenerationOptions(Converters = [typeof(AotResponseErrorConverter)])]
    [JsonSerializable(typeof(ArmEnvironment))]
    [JsonSerializable(typeof(Dictionary<string, Dictionary<string, JsonElement>>))]
    [JsonSerializable(typeof(Dictionary<string, string>))]
